function normalizeCleanTaxiLocale031A(input?: string | null): string {
  return String(input || '')
    .trim()
    .replace(/_/g, '-')
    .toLowerCase();
}

export function resolveCleanTaxiLocale031A(language: string): CleanTaxiLocale031A {
  const normalized = normalizeCleanTaxiLocale031A(language);
  const exact = cleanTaxiLocales031A.find((code) => normalizeCleanTaxiLocale031A(code) === normalized);
  if (exact) return exact;

  const base = normalized.split('-')[0];
  const baseMatch = cleanTaxiLocales031A.find((code) => normalizeCleanTaxiLocale031A(code) === base);
  return baseMatch ?? 'en';
}

export function useCleanTaxiText031A() {
  const locale = resolveCleanTaxiLocale031A(getAppLanguage());
  const dict = cleanTaxiDictionary031A[locale];
  return {
    locale,
    locales: cleanTaxiLocales031A,
    t(key: CleanTaxiCopyKey031A) {
      return dict[key];
    },
  };
}
